import heroMain from '../assets/about-insurekids/hero-main.png';
import problemComparison from '../assets/about-insurekids/problem-comparison.png';
import solutionScheme from '../assets/about-insurekids/solution-scheme.png';
import stepCreateCharacter from '../assets/about-insurekids/step-create-character.png';
import stepCards from '../assets/about-insurekids/step-cards.png';
import blogScreen from '../assets/about-insurekids/blog-screen.png';
import futureRoadmap from '../assets/about-insurekids/future-roadmap.png';
import finalCta from '../assets/about-insurekids/final-cta.png';

export const aboutHeroCards = [
  {
    title: 'Ситуация',
    text: 'Сломался телефон, сорвалась поездка или случилась другая жизненная неприятность.',
  },
  {
    title: 'Решение',
    text: 'Игрок сам формулирует ответ, а не угадывает правильную кнопку.',
  },
  {
    title: 'Результат',
    text: 'ИИ показывает последствия выбора и подводит к понятному выводу.',
  },
];

export const aboutMechanicsCards = [
  {
    title: 'Живой персонаж',
    text: 'У героя есть деньги, здоровье, настроение и собственная история, поэтому игра ощущается личной.',
  },
  {
    title: '30+ событий',
    text: 'Каждая карточка показывает знакомую жизненную ситуацию, а не абстрактный термин из учебника.',
  },
  {
    title: 'Свободный ответ',
    text: 'Игрок сам пишет, как поступит, поэтому не подстраивается под готовый список вариантов.',
  },
  {
    title: 'Адаптивный ИИ',
    text: 'Система учитывает контекст события, параметры героя и формулировку ответа.',
  },
  {
    title: 'Уровни сложности',
    text: 'Разный старт в игре помогает мягко входить в тему и постепенно усложнять опыт.',
  },
];

export const aboutLearningCards = [
  {
    title: 'Что такое риск',
    text: 'Подросток видит риск внутри знакомой сцены и быстрее связывает термин с реальной жизнью.',
  },
  {
    title: 'Что такое страховой случай',
    text: 'Игра показывает момент, когда проблема действительно случилась и уже требует решения.',
  },
  {
    title: 'Почему последствия важны',
    text: 'Каждое решение меняет состояние героя и учит думать не только о сейчас, но и о потом.',
  },
  {
    title: 'Где помогает страхование',
    text: 'Через примеры становится ясно, в каких ситуациях защита действительно снижает потери.',
  },
  {
    title: 'Как мыслить на несколько шагов вперёд',
    text: 'Игровые сценарии тренируют привычку оценивать риски и выбирать более разумный путь.',
  },
];

export const aboutFuturePoints = [
  'Система игровых концовок и персональных траекторий',
  'Механика выбора страховки внутри игрового цикла',
  'Индивидуальные сценарии под возраст и интересы игрока',
  'Интеграция с реальными продуктами и партнёрскими предложениями',
];

